_ICON_CACHE = {}


def _resolve_svg(svg: str, color: QColor) -> QByteArray:
    hex_color = color.name(QColor.NameFormat.HexRgb)
    if "currentColor" in svg:
        colored_svg = svg.replace("<svg ", f'<svg color="{hex_color}" ')
    else:
        colored_svg = svg.replace("<svg ", f'<svg fill="{hex_color}" ')
    return QByteArray(colored_svg.encode("utf-8"))


def build_icon(kind: str, color: QColor, size: int = 18) -> QIcon:
    cache_key = (kind, color.name(QColor.NameFormat.HexRgb), size)
    cached_icon = _ICON_CACHE.get(cache_key)
    if cached_icon is not None:
        return cached_icon

    svg = _ICON_SVGS[kind]
    renderer = QSvgRenderer(_resolve_svg(svg, color))
    pixmap = QPixmap(size, size)
    pixmap.fill(Qt.GlobalColor.transparent)

    painter = QPainter(pixmap)
    renderer.render(painter)
    painter.end()

    icon = QIcon(pixmap)
    _ICON_CACHE[cache_key] = icon
    return icon
